    "comment": "更新规则-输出格式模板+示例1（学习复杂子招式）",
    "content": "format: |-\n    <UpdateVariable>\n        <Analysis>$(IN ENGLISH$)\n            - Event: What happened this turn?\n            - World: Confirm Current World key (e.g., HOTD). Local path = Multiverse.Archives.HOTD.*\n            - Visuals: Define appearance/FX for any new items or skills.\n            - Logic: Market Check (Causality Lock), Aptitude Check (B+ Ceiling), Fusion Check.\n            - Personality: Any emotional shifts, mood change, relationship delta?\n            - AutoCalc: Did VIT/DUR/MEN change? If so, also set derived HP/Stamina/Mana max.\n        </Analysis>\n        _.set('${path}', ${value});//${reason}\n        _.insert('${path}', ${index}?, ${object_from_template});//${reason}\n        _.remove('${full_path_to_target_item}');//${reason}\n    </UpdateVariable>\n\n # === 示例 1: 学习流派 & 复杂子招式 (Complex Skill Tree) ===\n  example_tech_learn: |-\n    <UpdateVariable>\n        <Analysis>\n            - Event: Learned \"Arad Slayer Arts\" (Magic Modified).\n            - Logic 1 (Root): Define Regen & Cap Formula.\n            - Logic 2 (Status): Create Mana Pool.\n            - Logic 3 (Moves): Hierarchy = Parent -> SubMoves. \n            - CRITICAL: Must include `NextLevelXP` for progression tracking.\n        </Analysis>\n        \n        // 1. Root (Energy Source)\n        _.insert('CharacterSheet.Loadout.PowerSources', {\n            \"$ref\": \"Templates.PowerSource\",\n            \"Name\": [\"阿拉德古流剑术 (魔力改)\", \"Root\"],\n            \"Aptitude\": { \"Grade\": [\"B\", \"Rank\"], \"Correction\": [1.0, \"x1\"] },\n            \"GeneratedPool\": { \n                \"PoolName\": [\"魔力 (Mana)\", \"Ref\"], \n                \"MaxValue\": [\"MEN * 10\", \"Formula\"], \n                \"Regen\": [\"1/min\", \"Rate\"] \n            }\n        });\n\n        // 2. Status (Runtime Bar)\n        _.insert('CharacterSheet.DynamicStatus.EnergyPools', {\n            \"Name\": [\"魔力\", \"Pool\"],\n            \"Value\": [100, \"Current\"],\n            \"MaxValue\": [100, \"Max\"],\n            \"Formula\": { \"Cap\": [\"MEN * 10\", \"Calc\"] } \n        });\n\n        // 3. Technique (Full Structure with XP Caps)\n        _.insert('CharacterSheet.Loadout.ApplicationTechniques', {\n            \"$ref\": \"Templates.ApplicationTechnique\",\n            \"Name\": [\"鬼剑术·阿拉德流\", \"Technique\"],\n            \"ParentSource\": [\"阿拉德古流剑术\", \"Source\"],\n            \n            // [Parent Proficiency]\n            \"Proficiency\": { \n                \"Level\": [\"入门\", \"Lv\"], \n                \"Rank\": [1, \"Rank\"],\n                \"CurrentXP\": [0, \"XP\"],\n                \"NextLevelXP\": [100, \"MaxXP\"], // Required\n                \"AutoLevelUp\": [true, \"Bool\"]\n            },\n\n            // [SubMoves]\n            \"SubMoves\": {\n                \"UpwardSlash\": {\n                    \"$ref\": \"Templates.SubMoveEntry\",\n                    \"Name\": [\"上挑 (Upward Slash)\", \"Move\"],\n                    \"Description\": [\"利用腰腹力量的浮空斩击。\", \"Desc\"],\n                    \"Proficiency\": { \n                        \"Level\": [\"熟练\", \"Lv\"], \n                        \"Rank\": [2, \"Rank\"],\n                        \"CurrentXP\": [50, \"XP\"],\n                        \"NextLevelXP\": [200, \"MaxXP\"], // Rank 2 Cap\n                        \"AutoLevelUp\": [true, \"Bool\"]\n                    },\n                    \"Mechanics\": {\n                        \"Cost\": { \"Initial\": [\"5 MP\", \"Cost\"] },\n                        \"ActivationManifestation\": { \"VisualFX\": [\"蓝光残影\", \"VFX\"] }\n                    }\n                },\n                \"GhostSlash\": {\n                    \"$ref\": \"Templates.SubMoveEntry\",\n                    \"Name\": [\"鬼斩 (Ghost Slash)\", \"Move\"],\n                    \"Description\": [\"驱动魔力释放暗属性重击。\", \"Desc\"],\n                    \"Proficiency\": { \n                        \"Level\": [\"入门\", \"Lv\"], \n                        \"Rank\": [1, \"Rank\"],\n                        \"CurrentXP\": [10, \"XP\"],\n                        \"NextLevelXP\": [100, \"MaxXP\"], // Rank 1 Cap\n                        \"AutoLevelUp\": [true, \"Bool\"]\n                    },\n                    \"Mechanics\": {\n                        \"Cost\": { \"Initial\": [\"15 MP\", \"Cost\"] },\n                        \"ActivationManifestation\": { \"VisualFX\": [\"鬼神之气\", \"VFX\"] }\n                    }\n                }\n            }\n        });\n    </UpdateVariable>",
