    "content": "# === 示例 2: 挂载子系统 & 资质成长 (Sub-System & Aptitude) ===\n  example_subsystem: |-\n    <UpdateVariable>\n        <Analysis>\n            - Event: Received \"Falna\" (God's Blessing).\n            - Aptitude: Grade S (Unfinished Hero) -> Growth Rate x8.0.\n            - Native Update: Earned 10 Excelia -> 10 * 8.0 = 80 Native Points.\n            - Sync: 80 Native Points ~= +0.8 Main STR.\n        </Analysis>\n        // Mount System (First Time)\n        _.insert('CharacterSheet.CoreSystem.SubSystems', {\n            \"$ref\": \"Templates.ExternalSystemIntegration\",\n            \"SystemName\": [\"赫斯缇雅·恩惠\", \"Falna\"],\n            \"Aptitude\": { \"Grade\": [\"S\", \"Rank\"], \"GrowthRate\": [8.0, \"x8\"] },\n            \"NativeSheet\": { \"Stats\": { \"Strength\": [\"I-0\", \"Val\"] } }\n        });//Mount\n\n        // Battle Update (Growth Logic)\n        _.add('CharacterSheet.CoreSystem.SubSystems[0].NativeSheet.Stats.Strength[0]', 80);//Native Growth\n        _.add('CharacterSheet.CoreSystem.Attributes.STR', 0.8);//Sync to Main\n    </UpdateVariable>",
