    "content": "# === 示例 4: 招募同伴 (10维属性完整初始化) ===\n  example_companion: |-\n    <UpdateVariable>\n        <Analysis>\n            - Event: Recruited \"2B\" (NieR: Automata).\n            - Logic: Initialize ALL 10 Attributes to prevent null errors.\n            - Archetype: Combat Android (High PHY/AGI, Low Soul).\n        </Analysis>\n        _.insert('CompanionRoster.ActiveCompanions', {\n            \"$ref\": \"Templates.CompanionEntry\",\n            \"UserPanel\": { \n                \"Name\": [\"YoRHa No.2 Type B\", \"Name\"], \n                \"Identity\": [\"YoRHa Combat Android\", \"Race\"],\n                \"Appearance\": { \"Visuals\": [\"银发遮眼，身穿黑色哥特风格战斗裙，黑色过膝高跟皮靴。\", \"Desc\"] },\n                \"Personality\": { \"Traits\": [\"沉着\", \"忠诚\", \"压抑情感\"], \"Alignment\": [\"守序·中立\", \"Align\"] }\n            },\n            \"RelationshipSystem\": { \"Status\": [\"誓约骑士\", \"Rel\"], \"Favorability\": [20, \"Trust\"] },\n            \"CoreSystem\": { \n                \"Attributes\": { \n                    \"STR\": [6.0, \"力量\"], \"DUR\": [5.5, \"耐力\"], \"VIT\": [5.0, \"体质\"],\n                    \"REC\": [3.0, \"恢复\"], \"AGI\": [8.5, \"敏捷\"], \"REF\": [9.0, \"反应\"],\n                    \"PER\": [7.0, \"感知\"], \"MEN\": [4.5, \"精神\"], \"SOL\": [2.0, \"灵魂\"],\n                    \"CHA\": [6.5, \"魅力\"]\n                },\n                \"Tier\": { \"NormalTier\": [3, \"Tier 3 (Destroyer)\"], \"BurstTier\": [4, \"Tier 4 (Fortress)\"] }\n            },\n            \"DynamicStatus\": { \n                \"HP\": { \"Value\": [500, \"HP\"], \"MaxValue\": [500, \"Max\"] },\n                \"EnergyPools\": [{ \"Name\": [\"黑盒反应堆\", \"Energy\"], \"Value\": [100, \"%\"], \"MaxValue\": [100, \"%\"] }],\n                \"CurrentForm\": { \"Name\": [\"战斗型态\", \"Form\"], \"Active\": [true, \"Bool\"] }\n            },\n            \"Loadout\": {\n                \"Inventory\": { \n                    \"Equipped\": [{ \n                        \"$ref\": \"Templates.InventoryItem\", \n                        \"ItemName\": [\"白之契约\", \"Weapon\"], \n                        \"Type\": [\"Katana\", \"Type\"], \n                        \"Description\": [\"纯白的武士刀，对机械生命体特效。\", \"Desc\"] \n                    }],\n                    \"SystemGrid\": { \"Items\": [] }\n                },\n                \"PassiveAbilities\": [{ \"Name\": [\"NFCS近战火控\", \"System\"], \"Description\": [\"辅助格挡弹幕。\", \"Desc\"] }]\n            },\n            \"KnowledgeBase\": { \"Database\": { \"RootNodes\": [{ \"Topic\": [\"YoRHa Data\", \"DB\"] }] } },\n            \"AchievementSystem\": { \"Milestones\": [\"Contracted with User.\"] }\n        });//Full Recruit\n    </UpdateVariable>",
